sys_script_include.script:
var TableHTMLGenerator = Class.create();
TableHTMLGenerator.prototype = {
    initialize: function (params) {
        params = params || {};
        this.logger = params.logger;
        this.queryBuilder = params.queryBuilder;
    },

    getAppliedFiltersInfoMessage: function (appliedFilters) {
        appliedFilters = appliedFilters || [];
        var htmlString = "";

        try {
            for (var i = 0; i < appliedFilters.length; i++) {
                var filter = appliedFilters[i];
                var isLastFilter = i === appliedFilters.length - 1;

                // currentLogicalOp: what operator connects THIS filter with the NEXT one
                var currentLogicalOp =
                    i < appliedFilters.length - 1
                        ? String(appliedFilters[i].logicalOperator || "and")
                              .toLowerCase()
                              .trim()
                        : null;

                // prevLogicalOp: what operator connects the PREVIOUS filter with THIS one
                var prevLogicalOp =
                    i > 0
                        ? String(appliedFilters[i - 1].logicalOperator || "and")
                              .toLowerCase()
                              .trim()
                        : null;

                // Separator + open bracket when going from AND to OR
                if (i > 0) {
                    if (prevLogicalOp === "and" && currentLogicalOp === "or") {
                        htmlString +=
                            ' <span class="filter-separator filter-separator--and"><em>AND</em></span> <span class="filter-bracket-open">[</span> ';
                    } else if (prevLogicalOp === "and") {
                        htmlString +=
                            ' <span class="filter-separator filter-separator--and"><em>AND</em></span> ';
                    } else if (prevLogicalOp === "or") {
                        htmlString +=
                            ' <span class="filter-separator filter-separator--or"><em>OR</em></span> ';
                    }
                } else if (i === 0 && currentLogicalOp === "or") {
                    htmlString += '<span class="filter-bracket-open">[</span> ';
                }

                htmlString += this.getFilterHtml(filter);

                if (currentLogicalOp === "and" && prevLogicalOp === "or") {
                    htmlString +=
                        ' <span class="filter-bracket-close">]</span>';
                }

                if (isLastFilter && prevLogicalOp === "or") {
                    htmlString +=
                        ' <span class="filter-bracket-close">]</span>';
                }
            }
        } catch (error) {
            if (this.logger) {
                this.logger.error({
                    method: "getAppliedFiltersInfoMessage",
                    message: "Error generating applied filters info message",
                    error: error.message,
                    appliedFilters: appliedFilters,
                });
            }
        }

        return htmlString;
    },

    getFilterHtml: function (filter) {
        if (filter.type === "reference") {
            var operatorLabel = this.queryBuilder.getOperatorLabel(
                filter.operator,
            );

            // Use displayValue if available (pre-resolved by server)
            // Fallback to value if displayValue is not available
            var referenceDisplayValue =
                filter.displayValue || filter.value || "";

            if (this.queryBuilder.operatorNeedsValue(filter.operator)) {
                /* prettier-ignore */
                return "<span>" + this.escapeHtml(filter.label) + " <em>" + this.escapeHtml(operatorLabel) + "</em> " + this.escapeHtml(referenceDisplayValue) + "</span>";
            } else {
                /* prettier-ignore */
                return "<span>" + this.escapeHtml(filter.label) + " <em>" + this.escapeHtml(operatorLabel) + "</em></span>";
            }
        }

        if (filter.type === "choice") {
            var choiceValues = filter.choiceValues || [];
            var displayValue = filter.value;
            var choiceOperatorLabel = this.queryBuilder.getOperatorLabel(
                filter.operator,
            );

            for (var j = 0; j < choiceValues.length; j++) {
                if (choiceValues[j].value === filter.value) {
                    displayValue = choiceValues[j].label;
                    break;
                }
            }

            if (this.queryBuilder.operatorNeedsValue(filter.operator)) {
                /* prettier-ignore */
                return "<span>" + this.escapeHtml(filter.label) + " <em>" + this.escapeHtml(choiceOperatorLabel) + "</em> " + this.escapeHtml(displayValue) + "</span>";
            } else {
                /* prettier-ignore */
                return "<span>" + this.escapeHtml(filter.label) + " <em>" + this.escapeHtml(choiceOperatorLabel) + "</em></span>";
            }
        }

        if (filter.type === "string") {
            var stringOperatorLabel = this.queryBuilder.getOperatorLabel(
                filter.operator,
            );

            if (this.queryBuilder.operatorNeedsValue(filter.operator)) {
                var valueLabel = filter.value;

                if (
                    filter.operator === "between" &&
                    filter.valueTo != null &&
                    filter.valueTo !== ""
                ) {
                    valueLabel += " and " + filter.valueTo;
                }

                /* prettier-ignore */
                return "<span>" + this.escapeHtml(filter.label) + " <em>" + this.escapeHtml(stringOperatorLabel) + "</em> " + this.escapeHtml(valueLabel) + "</span>";
            } else {
                /* prettier-ignore */
                return "<span>" + this.escapeHtml(filter.label) + " <em>" + this.escapeHtml(stringOperatorLabel) + "</em></span>";
            }
        }

        if (filter.type === "date") {
            var dateOperatorLabel = this.queryBuilder.getOperatorLabel(
                filter.operator,
            );

            if (this.queryBuilder.operatorNeedsValue(filter.operator)) {
                var dateValueLabel = filter.value;

                if (
                    filter.operator === "between" &&
                    filter.valueTo != null &&
                    filter.valueTo !== ""
                ) {
                    dateValueLabel += " and " + filter.valueTo;
                }

                /* prettier-ignore */
                return "<span>" + this.escapeHtml(filter.label) + " <em>" + this.escapeHtml(dateOperatorLabel) + "</em> " + this.escapeHtml(dateValueLabel) + "</span>";
            } else {
                /* prettier-ignore */
                return "<span>" + this.escapeHtml(filter.label) + " <em>" + this.escapeHtml(dateOperatorLabel) + "</em></span>";
            }
        }

        if (filter.type === "column_contains") {
            /* prettier-ignore */
            return "<span>" + this.escapeHtml(filter.label) + " <em>contains</em> " + this.escapeHtml(filter.value) + "</span>";
        }

        return "";
    },

    escapeHtml: function (value) {
        return String(value == null ? "" : value)
            .replace(/&/g, "&amp;")
            .replace(/</g, "&lt;")
            .replace(/>/g, "&gt;")
            .replace(/\"/g, "&quot;")
            .replace(/'/g, "&#39;");
    },

    type: "TableHTMLGenerator",
};
